export type DataCategory = 'general' | 'health' | 'sensitive_health'

export interface FormField {
  id: string;
  type: string;
  label: string;
  required: boolean;
  options?: string[];
  helpText?: string;
  conditionalShowIf?: { fieldId: string; value: string };
}

export interface FormTemplate {
  id: string;
  name: string;
  description?: string;
  fields: FormField[];
  requires_signature: boolean;
  gdpr_consent_text?: string;
  is_active: boolean;
}

const FIELD_TYPES = [
  { value: 'text', label: 'Tekst' },
  { value: 'textarea', label: 'Długi tekst' },
  { value: 'checkbox', label: 'Checkboxes' },
  { value: 'radio', label: 'Radio' },
  { value: 'select', label: 'Lista' },
  { value: 'date', label: 'Data' },
  { value: 'signature', label: 'Podpis' },
  { value: 'section_header', label: 'Nagłówek sekcji' },
];

