const seenBuiltinTemplateNames = new Set<string>();
for (let index = BUILTIN_TEMPLATES.length - 1; index >= 0; index -= 1) {
  const templateName = BUILTIN_TEMPLATES[index]?.name;
  if (!templateName) {
    continue;
  }

  if (seenBuiltinTemplateNames.has(templateName)) {
    BUILTIN_TEMPLATES.splice(index, 1);
    continue;
  }

  seenBuiltinTemplateNames.add(templateName);
}

export type BuiltinFormTemplate=Omit<FormTemplate,"id"|"is_active"> & { data_category?: DataCategory };
